31		proc sal_print_log {text} {
32			variable Simulator
33			variable TranscriptFile
34			if {$Simulator == "Modelsim"} {
35				echo $text
36			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
37				#Console
38				puts $text
39				#Transcript
40				set fo [open $TranscriptFile a]
41				puts $fo $text
42				close $fo			
43			} else {
44				puts "ERROR: Unsupported Simulator - sal_print_log(): $Simulator"
45			}
46		}
