51				transcript off
52			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
53				#Nothing to do
54			} else {
55				puts "ERROR: Unsupported Simulator - sal_transcript_off(): $Simulator"
56			}
57		}
