82		proc sal_clean_transcript {} {
83			variable Simulator
84			sal_transcript_off
85			if {$Simulator == "Modelsim"} {
86				sal_set_transcript_file ./Dummy.transcript
87				set bm [batch_mode]
88				if {$bm == 0} {
89					file delete ./Transcript.transcript
90				}
91				sal_set_transcript_file ./Transcript.transcript
92				file delete ./Dummy.transcript
93			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
94				file delete ./Transcript.transcript
95				sal_set_transcript_file ./Transcript.transcript
96				return
97			} else {
98				puts "ERROR: Unsupported Simulator - sal_clean_transcript(): $Simulator"
99			}
100			sal_transcript_on
101		}
