104		proc sal_version_specific_flags {} {
105			variable Simulator
106			variable SimulatorVersion
107			set args ""
108			if {$Simulator == "Modelsim"} {
109				if {[expr $SimulatorVersion < 10.7]} {
110					set args "$args -novopt"
111				}			
112			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
113				#Nothing to do
114			} else {
115				puts "ERROR: Unsupported Simulator - sal_version_specific_flags(): $Simulator"
116			}
117			
118			return $args
119		}
