121		proc sal_init_simulator {} {
122			variable Simulator
123			if {$Simulator == "Modelsim"} {
124				#The vsim -version command does not return the version but write it to stdout. Therefore this is
125				#.. forwareded to a file and read back from there. A sleep is required because writing the
126				#.. file takes some time. 
127				#.. Modelsim prints a warning because the stdout is forwarded to a file. Unfortunately I could not
128				#.. find any way to suppress this warning (the forwarding is fully okay and expected).
129				puts ">>> Error expected ..."
130				vcom -version >tempVersion.txt
131				puts ">>> ... until here."
132				after 500			
133				set txtFile [open tempVersion.txt]; list
134				set versionStr [read $txtFile]; list
135				close $txtFile
136				file delete tempVersion.txt
137				regexp {\s([0-9\.]+)\s} $versionStr dummy versionNr
138				variable SimulatorVersion $versionNr
139				puts "ModelsimVersion: $versionNr"
140			} elseif {$Simulator == "GHDL"} {
141				variable SimulatorVersion "NotImplementedForGhdl"
142			} elseif {$Simulator == "Vivado"} {
143				variable SimulatorVersion "NotImplementedForvivado"			
144			} else {
145				puts "ERROR: Unsupported Simulator - sal_init_simulator(): $Simulator"
146			}
147		}
