149		proc sal_clean_lib {lib} {
150			variable Simulator
151			if {$Simulator == "Modelsim"} {
152				vlib $lib
153				vdel -all -lib $lib
154				vlib $lib
155			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
156				file delete -force $lib
157			} else {
158				puts "ERROR: Unsupported Simulator - sal_clean_lib(): $Simulator"
159			}
160		}
