162		proc sal_compile_file {lib path language langVersion fileOptions} {
163			variable Simulator
164			variable CompileSuppress 
165			set vFlags [sal_version_specific_flags]
166			if {$Simulator == "Modelsim"} {			
167				set args "-work $lib $vFlags -suppress $CompileSuppress $fileOptions -quiet $path"
168				if {$language == "vhdl"} {
169					lappend args "-$langVersion"
170					vcom {*}$args
171				} else {
172					lappend args "-incr"
173					vlog {*}$args
174				}
175			} elseif {$Simulator == "GHDL"} {
176				if {$language == "vhdl"} {
177					if {$langVersion == "2002"} {
178						# compile for 2002 (to make sure no 2008 features are used) but compile again for 2008
179						# since we assume most testbenches will use that and ghdl does not support mixing versions
180						file mkdir $lib/v93
181						exec ghdl -a --ieee=synopsys --std=02 -fexplicit -frelaxed-rules -Wno-shared -Wno-hide --workdir=$lib/v93 --work=$lib -P. $path
182					} elseif {$langVersion != "2008"} {
183						sal_print_log "ERROR: VHDL Version $langVersion not supported for GHDL"
184					}
185					file mkdir $lib/v08
186					exec ghdl -a --ieee=synopsys --std=08 -frelaxed-rules -Wno-shared -Wno-hide --workdir=$lib/v08 --work=$lib -P. $path
187				} else {
188					sal_print_log "ERROR: Verilog currently not supported for GHDL"
189					sal_print_log ""
190				}
191			} elseif {$Simulator == "Vivado"} {		
192				if {$language == "vhdl"} {
193					set langArg ""
194					if {$langVersion == "2008"} {
195						set langArg "--2008"
196					}
197				} else {
198					sal_print_log "ERROR: Verilog currently not supported for Vivado, request this feature from the developers"
199					sal_print_log ""
200				}
201				# langArg may be empty and confuse xvhdl; therefore we 'eval'...
202				eval exec xvhdl --lib=$lib --work $lib=$lib $langArg $path
203			} else {
204				puts "ERROR: Unsupported Simulator - sal_compile_file(): $Simulator"
205			}
206		}
