208		proc sal_exec_script {path cmd args} {
209			variable Simulator
210			set oldPath [pwd]
211			cd $path
212			sal_print_log "Running Pre Script"
213			if {$Simulator == "Modelsim"} {
214				sal_print_log [exec $cmd $args]
215			} elseif {($Simulator == "GHDL") || ($Simulator == "Vivado")} {
216				set outp [exec $cmd $args]
217				sal_print_log $outp
218			} else {
219				puts "ERROR: Unsupported Simulator - sal_exec_script(): $Simulator"
220			}
221			cd $oldPath
222		}
