224		proc sal_run_tb {lib tbName tbArgs timeLimit suppressMsgNo {wave ""}} {
225			variable Simulator
226			if {$Simulator == "Modelsim"} {
227				set supp ""
228				if {$suppressMsgNo != ""} {
229					set supp +nowarn$suppressMsgNo
230				}
231				set cmd "vsim -quiet -t 1ps -msgmode both $supp $lib.$tbName $tbArgs"
232				eval $cmd
233				set StdArithNoWarnings 1
234				set NumericStdNoWarnings 1
235				if {$timeLimit != "None"} {
236					run $timeLimit
237				} else {
238					run -all
239				}
240				quit -sim
241			} elseif {$Simulator == "GHDL"} {
242				if {$tbArgs != ""} {
243					set tbArgs " $tbArgs"
244				}
245				if {$timeLimit != "None"} {
246					sal_print_log "Stop $timeLimit"
247					set stopTime " --stop-time=[string map {" " ""} $timeLimit]"
248				} else {
249					set stopTime ""
250				}
251				if {$wave != ""} {
252					set wave " --wave=$wave"
253				} 
254				set cmd "ghdl --elab-run --ieee=synopsys --std=08 -frelaxed-rules -Wno-shared --workdir=$lib/v08 --work=$lib $tbName$tbArgs$stopTime$wave --ieee-asserts=disable"
255				sal_print_log $cmd
256				set outp [eval "exec $cmd"]
257				sal_print_log $outp
258			} elseif {$Simulator == "Vivado"} {
259				#Write propper initfile (workaround because --lib switch of xelab does not work)
260				variable Libraries
261				set initFile psi_vivado_init.ini
262				file delete $initFile
263				set fo [open $initFile w+]
264				foreach lib $Libraries {
265					puts $fo "$lib=$lib\n"
266				}
267				close $fo	
268				#Find generic overrides
269				set genericOverrides ""
270				foreach param $tbArgs {
271					if {[string match "-g*" $param]} {
272						lappend genericOverrides "-generic_top [string range $param 2 end]"
273					}
274				}
275				set genericOverrides [join $genericOverrides " "]
276				#Elaborate
277				set cmd "xelab --initfile $initFile -s psi_sim_snapshot -debug typical"
278				if {$genericOverrides != ""} {
279					set cmd "$cmd $genericOverrides"
280				}
281				set cmd "$cmd $lib.$tbName"
282				sal_print_log "$cmd"
283				eval "exec $cmd"
284				#Create simulation tcl file
285				set outputFile psi_sim_output.txt
286				file delete -force $outputFile
287				set simTclName "psi_sim_run.tcl"
288				set fo [open $simTclName w+]
289				if {$timeLimit != "None"} {
290					puts $fo "run $timeLimit > $outputFile;"
291				} else {
292					puts $fo "run -all > $outputFile;"
293				}
294				puts $fo "exit" 
295				close $fo
296				set cmd "xsim psi_sim_snapshot -tclbatch $simTclName"
297				sal_print_log "$cmd"
298				eval "exec $cmd"	
299				#Add aoutput to log
300				set fo [open $outputFile r]
301				sal_print_log [read $fo]
302				close $fo
303						
304			} else {
305				puts "ERROR: Unsupported Simulator - sal_run_tb(): $Simulator"
306			}
307		}
308	
309		proc sal_launch_tb {lib tbName tbArgs suppressMsgNo wave} {
310			variable Simulator
311			if {$Simulator == "Modelsim"} {
312				set supp ""
313				if {$suppressMsgNo != ""} {
314					set supp +nowarn$suppressMsgNo
315				}
316				set cmd "vsim -quiet -t 1ps -msgmode both $supp $lib.$tbName $tbArgs"
317				eval $cmd
318				set StdArithNoWarnings 1
319				set NumericStdNoWarnings 1
320				if {$wave != ""} {
321					if {$wave != "all"} {
322						sal_print_log "Restoring Waveform View $wave"
323						set cmd "do $wave"
324					} else {
325						sal_print_log "Adding all Signals to the Waveform View"
326						set cmd "add wave -r /*; run -all; wave zoom full"
327					}
328					eval $cmd
329				}
330			} else {
331				puts "ERROR: Unsupported Simulator - sal_launch_tb(): $Simulator"
332			}
333		}
