347		# Initialize PSI Simulation Package. This must be called as first command to use the library.
348		#
349		# -ghdl		Use GHDL instead of modelsim (modelsim is default)
350		# -vivado	Use Vivado Simulator instead of modelsim (modelsim is default)
351		proc init {args} {
352			puts "Initialize PsiSim"
353			set argList [split $args]
354			variable Simulator "Modelsim"
355			set i 0		
356			while {$i < [llength $argList]} {
357				set thisArg [lindex $argList $i]
358				if {$thisArg == "-ghdl"} {
359					variable Simulator "GHDL"
360				} elseif {$thisArg == "-vivado"} {
361					variable Simulator "Vivado"
362				} else {
363					sal_print_log "WARNING: ignored argument $thisArg"
364					sal_print_log ""
365				}
366				set i [expr $i + 1]
367			}
368			variable Libraries [list]
369			variable Sources [list]
370			variable TbRuns [list]
371			variable CompileSuppress ""
372			variable RunSuppress ""
373			variable CurrentLib "NoCurrentLibrary"
374			#Simulator specific initialization
375			sal_init_simulator
376			#Clean transcript
377			clean_transcript
378		}
