391		# Add one or more message numbers to the list of messages to ignore during compilation
392		#
393		# @param msgNos		One or more message numbers to suppress, speparated by comma
394		proc compile_suppress {msgNos} {
395			variable CompileSuppress 
396			set msgList [split $msgNos]
397			foreach msg $msgList {
398				#Only add to the list if it is not yet in the list
399				set exists [regexp -nocase $msg $CompileSuppress]
400				if {$exists == 0} {
401					variable CompileSuppress $CompileSuppress$msg,
402				}
403			}		
404		}
