408		#
409		# @param msgNos		One or more message numbers to suppress, speparated by comma
410		proc run_suppress {msgNos} {
411			variable RunSuppress 
412			set msgList [split $msgNos]
413			foreach msg $msgList {
414				#Only add to the list if it is not yet in the list
415				set exists [regexp -nocase $msg $RunSuppress]
416				if {$exists == 0} {
417					variable RunSuppress $RunSuppress$msg,
418				}
419			}
420		}
