423		# Add HDL source files (including testbenches)
424		#
425		# Variable Arguments:
426		#
427		# @param directory	Directory the source files are including
428		# @param files		List of file namespace
429		# -lib <name>		Name of the library to compile the files into. This parameter is optional, if it
430		#					is omitted, all files are compiled to the last library created with add_library
431		# -tag <name>		Optional tag that can be used to compile/run user selected groups of files
432		# -language <name>	Language (either "vhdl" or "verilog"). VHDL is default
433		# -version <year>	VHDL Version year to compile. Only used with VHDL. 2008 is default
434		# -options <string>	Modelsim Options to add as a string. No options is default
435		proc add_sources {directory files {args}} {
436			#parse arguments
437			variable CurrentLib
438			set tgtLib $CurrentLib
439			set tag ""
440			set language "vhdl"
441			set version "2008"
442			set options ""
443			set argList [split $args]
444			set i 0		
445			while {$i < [llength $argList]} {
446				set thisArg [lindex $argList $i]
447				if {$thisArg == "-lib"} {
448					set i [expr $i + 1]
449					set thisArg [lindex $argList $i]
450					set tgtLib $thisArg
451				} elseif {$thisArg == "-tag"} {
452					set i [expr $i + 1]
453					set thisArg [lindex $argList $i]
454					set tag $thisArg	
455				} elseif {$thisArg == "-language"} {
456					set i [expr $i + 1]
457					set thisArg [lindex $argList $i]
458					set language $thisArg
459				} elseif {$thisArg == "-version"} {
460					set i [expr $i + 1]
461					set thisArg [lindex $argList $i]
462					set version $thisArg
463				} elseif {$thisArg == "-options"} {
464					set i [expr $i + 1]
465					set thisArg [lindex $argList $i]
466					set options $thisArg
467				} else {
468					sal_print_log "WARNING: ignored argument $thisArg"
469					sal_print_log ""
470				}
471				set i [expr $i + 1]
472			}
473			#Add files
474			variable Sources
475			foreach patt $files {
476				set normalizedPatt [file normalize [concat $directory/$patt]]
477				if { ! [ catch {set found [glob $normalizedPatt]} ] } {
478					foreach path $found {
479						set ThisSrc [dict create]
480						dict set ThisSrc PATH $path
481						dict set ThisSrc LIBRARY $tgtLib
482						dict set ThisSrc TAG $tag
483						dict set ThisSrc LANGUAGE $language
484						dict set ThisSrc VERSION $version
485						dict set ThisSrc OPTIONS $options
486	#check if the file already exists for this library
487						foreach entry $Sources {
488							set ePath [dict get $entry PATH]
489								set eLib [dict get $entry LIBRARY]
490								if {($path == $ePath) && ($tgtLib == $eLib)} {
491									sal_print_log "WARNING: file $ePath already added to library $eLib"
492								}
493						}
494						# FIXME: should we omit appending existing source again?
495						#        keep existing behaviour for now...
496						lappend Sources $ThisSrc
497					}
498				} else {
499					sal_print_log "WARNING: file/pattern $normalizedPatt not found - skipping"
500				}
501			}
502		}
503		namespace export add_sources
