505		# Cleanup one or more libraries
506		#
507		# Variable Arguments:
508		# -all			Clean all libraries (if no argument is passed, -all is executed)
509		# -lib <name>	Name of one specific library to clean
510		proc clean_libraries {args} {
511			#Parse Arguments
512			set Library "All-Libraries"
513			set argList [split $args]
514			set i 0		
515			while {$i < [llength $argList]} {
516				set thisArg [lindex $argList $i]
517				if {$thisArg == "-all"} {
518					set Library "All-Libraries"
519				} elseif {$thisArg == "-lib"} {
520					set i [expr $i + 1]
521					set thisArg [lindex $argList $i]
522					set Library $thisArg
523				} else {
524					sal_print_log "WARNING: ignored argument $thisArg"
525					sal_print_log ""
526				}
527				set i [expr $i + 1]
528			}	
529			#Clean
530			variable Libraries
531			foreach lib $Libraries {
532				if {($Library == "All-Libraries") || ($Library == $lib)} {
533					sal_print_log "cleanup $lib"
534					sal_clean_lib $lib
535				}
536			}
537		}
538		namespace export clean_libraries
539		
540		# Compile source files
541		#
542		# Variable Arguments:
543		# -all				Compile all source files
544		# -lib <name>		Only compile this library
545		# -tag <name>		Only compile files with this tag
546		# -clean			Clean libraries before compiling
547		# -contains <str>	Compile only if path to the file contains a given string
548		proc compile {args} {
549			#Parse Arguments
550			set Library "All-Libraries"
551			set Tag "All-Tags"
552			set argList [split $args]
553			set clean false
554			set contains "All-regex"
555			set i 0		
556			while {$i < [llength $argList]} {
557				set thisArg [lindex $argList $i]
558				if {$thisArg == "-all"} {
559					set Library "All-Libraries"
560				} elseif {$thisArg == "-lib"} {
561					set i [expr $i + 1]
562					set thisArg [lindex $argList $i]
563					set Library $thisArg
564				} elseif {$thisArg == "-clean"} {
565					set clean true
566				} elseif {$thisArg == "-tag"} {
567					set i [expr $i + 1]
568					set thisArg [lindex $argList $i]
569					set Tag $thisArg
570				} elseif {$thisArg == "-contains"} {
571					set i [expr $i + 1]
572					set thisArg [lindex $argList $i]
573					set contains $thisArg			
574				} else {
575					sal_print_log "WARNING: ignored argument $thisArg"
576					sal_print_log ""
577				}
578				set i [expr $i + 1]
579			}
580			#Clean if required
581			if {$clean} {
582				clean_libraries -lib $Library
583			}
584			#Compile
585			variable CompileSuppress 
586			variable Sources
587			foreach file $Sources {
588				set thisFileLib [dict get $file LIBRARY]
589				set thisFileTag [dict get $file TAG]
590				set thisFilePath [dict get $file PATH]
591				set thisFileLanguage [dict get $file LANGUAGE]
592				set thisFileVersion [dict get $file VERSION]
593				set thisFileOptions [dict get $file OPTIONS]
594				if {($Library != "All-Libraries") && ($Library != $thisFileLib)} {
595					continue
596				}
597				if {($Tag != "All-Tags") && ($Tag != $thisFileTag)} {
598					continue
599				}
600				if {($contains != "All-regex") && ([string first $contains $thisFilePath] == -1)} {
601					continue
602				}
603				#Execute compilation
604				sal_print_log "$thisFileLib - Compile [file tail $thisFilePath]"
605				sal_compile_file $thisFileLib $thisFilePath $thisFileLanguage $thisFileVersion $thisFileOptions
606			}
607		}
608		#Wrapper to prevent name clash with modelsim "compile"
609		proc compile_files {args} {
610			set jonedArgs [join $args]
611			eval "compile $jonedArgs"
612		}
613		namespace export compile_files
614		
615		# Creat a testbench run. A testbench run consists of a pre-script (run before TB), a post script (ran after TB) and optionally
616		# different arguments to pass to the TB for multiple simulations. 
617		# Note that the TB run is only added with the separate command add_tb_run
618		#
619		# @param tb			Name of the testbench to run
620		# @param library	Name of the library the testbench is in. This parameter is optional, if it
621		#					is omitted, it is assumed the TB is in the last library created with add_library 
622		proc create_tb_run {tb {library "None"}} {
623		
624			#Select tb library
625			variable CurrentLib
626			set tbLib $library
627			if {$tbLib == "None"} {
628				set tbLib $CurrentLib
629			}	
630			#Implementation
631			variable ThisTbRun [dict create]
632			dict set ThisTbRun TB_NAME $tb
633			dict set ThisTbRun TB_LIB $tbLib
634			dict set ThisTbRun TB_ARGS [list ""]
635			dict set ThisTbRun PRESCRIPT_CMD ""
636			dict set ThisTbRun PRESCRIPT_PATH "."
637			dict set ThisTbRun PRESCRIPT_ARGS ""
638			dict set ThisTbRun POSTSCRIPT_CMD ""
639			dict set ThisTbRun POSTSCRIPT_PATH "."
640			dict set ThisTbRun POSTSCRIPT_ARGS ""	
641			dict set ThisTbRun TIME_LIMIT "None"
642	        dict set ThisTbRun SKIP "None"
643		}
644		namespace export create_tb_run
645		
646		# Add a pre-script to the last TB run created with create_tb_run. It must be called between create_tb_run and add_tb_run.
647		#
648		# @param cmd		Command for the pre-script
649		# @param args		Arguments to pass to the command
650		# @param path		Working directory to execute the command in
651		proc tb_run_add_pre_script {{cmd ""} {args ""} {path ""}} {
652			variable ThisTbRun
653			dict set ThisTbRun PRESCRIPT_CMD $cmd
654			dict set ThisTbRun PRESCRIPT_ARGS $args
655			if {$path != ""} {
656				dict set ThisTbRun PRESCRIPT_PATH [file normalize $path]
657			}
658		}
659		namespace export tb_run_add_pre_script
660		
661		# Add a post-script to the last TB run created with create_tb_run. It must be called between create_tb_run and add_tb_run.
662		#
663		# @param cmd		Command for the post-script
664		# @param args		Arguments to pass to the command
665		# @param path		Working directory to execute the command in	
666		proc tb_run_add_post_script {{cmd ""} {args ""} {path ""}} {
667			variable ThisTbRun
668			dict set ThisTbRun POSTSCRIPT_CMD $cmd
669			dict set ThisTbRun POSTSCRIPT_ARGS $args
670			if {$path != ""} {
671				dict set ThisTbRun POSTSCRIPT_PATH [file normalize $path]
672			}
673		}	
674		namespace export tb_run_add_post_script
675		
676		# Specify different arguments set (e.g. generic values) to execute the TB for. It must be called between create_tb_run and add_tb_run.
677		#
678		# @param args		List of argument strings in the form "stringa" "stringB"
679		proc tb_run_add_arguments {args} {
680			variable ThisTbRun
681			dict set ThisTbRun TB_ARGS $args
682		}
683		namespace export tb_run_add_arguments
684		
685		# Specify an end-time for a tb-run. Usually testbenches should stop on their own but in some cases (e.g. if Xilinx primitives do keep the simulation running and run -all is not workgin),
686		# it may be required to limit the runtime.
687		#
688		# @param limit		Time limit in the form "100 us"
689		proc tb_run_add_time_limit {limit} {
690			variable ThisTbRun
691			dict set ThisTbRun TIME_LIMIT $limit
692		}
693		namespace export tb_run_add_time_limit
694	    
695	    # Skip this testbench for one or all simulators
696	    #
697	    # @param simulator  Simulator to skip the TB for (use "GHDL", "Modelsim" or "all")
698	    proc tb_run_skip {{simulator "all"}} {
699	        variable ThisTbRun
700	        dict set ThisTbRun SKIP $simulator
701	    }
702	    namespace export tb_run_skip
703		
704		# This command must be called when a TB run created with create_tb_run is fully specified and can be added. The TB run cannot be modified after
705		# this command is called
706		proc add_tb_run {} {
707			variable TbRuns
708			variable ThisTbRun
709			lappend TbRuns $ThisTbRun; list
710		}
711		namespace export add_tb_run
712		
713		# Internal Function
714		proc clean_transcript {} {
715			sal_clean_transcript
716		}
717		
718		# Check if the transcript file contains a specific error string. Note that the string "Fatal:" is also interpreted as error.
719		#
720		# @param errorString	Error string to search for (should be included in all error messages)
721		proc run_check_errors {errorString} {
722			#Read transcript
723			sal_transcript_off
724			set transcriptFile [open "./Transcript.transcript" r]
725			set transcriptContent [read "$transcriptFile"]; list
726			close $transcriptFile
727			#Suppress the command call from analysis
728			regsub -all -linestop {.*run_check_errors.*} $transcriptContent "" transcriptContent		
729			#Search for string
730			set found [regexp -nocase $errorString $transcriptContent]
731			set foundFatal [regexp -nocase {Fatal:} $transcriptContent]
732			sal_print_log $found
733			sal_print_log $foundFatal
734			if {($found == 1) || ($foundFatal == 1)} {
735				sal_print_log "!!! ERRORS OCCURED IN SIMULATIONS !!!"		
736			} else {
737				sal_print_log "SIMULATIONS COMPLETED SUCCESSFULLY"
738			}
739		}
740		namespace export run_check_errors
741		
742		# Run one or more testbenches. The transcript is cleaned automatically before running the tesbenches. Pre- and Post-Scripts 
743		# executed automatically if they were specified.
744		#
745		# Variable Arguments:
746		# -all				Run all testbenches
747		# -lib <name>		Only run testbenches in this library
748		# -name <name>		Only run testbench with this name
749		# -contains <str>	Run only if testbench name contains a given string
750		#
751		# Note that -lib and -name can be combined to choose one specific testbench	
752		proc run_tb {args} {
753			
754			#Parse Arguments
755			set Library "All-Libraries"
756			set Name "All-Names"
757			set contains "All-regex"
758			set argList [split $args]
759			set i 0		
760			while {$i < [llength $argList]} {
761				set thisArg [lindex $argList $i]
762				if {$thisArg == "-all"} {
763					set Library "All-Libraries"
764					set Name "All-Names"
765				} elseif {$thisArg == "-lib"} {
766					set i [expr $i + 1]
767					set thisArg [lindex $argList $i]
768					set Library $thisArg
769				} elseif {$thisArg == "-name"} {
770					set i [expr $i + 1]
771					set thisArg [lindex $argList $i]
772					set Name $thisArg
773				} elseif {$thisArg == "-contains"} {
774					set i [expr $i + 1]
775					set thisArg [lindex $argList $i]
776					set contains $thisArg
777				} else {
778					sal_print_log "WARNING: ignored argument $thisArg"
779					sal_print_log ""
780				}
781				set i [expr $i + 1]
782			}
783			#Clean Transcript
784			clean_transcript
785			#Run
786			variable TbRuns
787			variable RunSuppress
788			variable Simulator
789			foreach run $TbRuns {
790				#Check if TB should be run
791				set runLib [dict get $run TB_LIB]
792				set runName [dict get $run TB_NAME]
793				set skip [dict get $run SKIP]
794				if {($runLib != $Library) && ($Library != "All-Libraries")} {
795					continue
796				}
797				if {($runName != $Name) && ($Name != "All-Names")} {
798					continue
799				}
800				if {($contains != "All-regex") && ([string first $contains $runName] == -1)} {
801					continue
802				}
803				sal_print_log ""
804				sal_print_log "******************************************************"
805				sal_print_log "*** Run $runLib.$runName"
806				sal_print_log "******************************************************"
807	            if {([lsearch $skip $Simulator] != -1) || ($skip == "all")} {
808	                sal_print_log "!!! Skipped for '$skip' !!!"
809	                continue
810	            }
811			
812				#Execute pre-script if required
813				set PsCmd [dict get $run PRESCRIPT_CMD]
814				set PsPath [dict get $run PRESCRIPT_PATH]
815				set PsArgs [dict get $run PRESCRIPT_ARGS]
816				if {($PsCmd != "")} {
817					sal_exec_script $PsPath $PsCmd $PsArgs
818				}
819				
820				#Execute TB for all arguments
821				sal_print_log "Running Simulation"
822				set allArgLists [dict get $run TB_ARGS]
823				set timeLimit [dict get $run TIME_LIMIT]
824				foreach tbArgs $allArgLists {
825					#Tun TB
826					sal_run_tb $runLib $runName $tbArgs $timeLimit $RunSuppress
827				}
828				#Execute pre-script if required
829				set PsCmd [dict get $run POSTSCRIPT_CMD]
830				set PsPath [dict get $run POSTSCRIPT_PATH]
831				set PsArgs [dict get $run POSTSCRIPT_ARGS]
832				if {($PsCmd != "")} {
833					sal_exec_script $PsPath $PsCmd $PsArgs
834				}		
835				
836			}
837			sal_transcript_off
838		}
839		namespace export run_tb	
840		
841		# Launch a testbench and keep the simulator window open for interactive debugging. Because this is meant for
842		# interactive debugging and not for regression test, neither pre- nor post-scripts are ran.
843		# By default, the TB is run with the default generic values from the sources. Alternatively the user can choose
844		# the generics combination to used (if specified with tb_run_add_arguments).
845		# The test-run is only launched but not executed. Execution is controlled interactively.
846		#
847		# Variable Arguments:
848		# -contains <str>	Run only if testbench name contains a given string (required!)
849		# -argidx   <int>	Index of the arguments from tb_run_add_arguments (0 = use first argument-list)
850		#
851		# Note that currently this command is only supported for Modelsim
852		proc launch_tb {args} {
853		
854			#Only Modelsim is supported currently for this debug command
855			variable Simulator
856			if {($Simulator != "Modelsim") && ($Simulator != "GHDL")} {
857				sal_print_log "ERROR: launch_tb: this command is only implemented for Modelsim and GHDL"
858				return
859			}	
860	
861			#Parse Arguments
862			set contains "All-regex"
863			set argidx "default"
864			set wave ""
865			set show ""
866			set argList [split $args]
867			set i 0		
868			while {$i < [llength $argList]} {
869				set thisArg [lindex $argList $i]
870				if {$thisArg == "-contains"} {
871					set i [expr $i + 1]
872					set thisArg [lindex $argList $i]
873					set contains $thisArg
874				} elseif {$thisArg == "-argidx"} {
875					set i [expr $i + 1]
876					set thisArg [lindex $argList $i]
877					set argidx $thisArg
878				} elseif {$thisArg == "-wave"} {
879					set i [expr $i + 1]
880					set thisArg [lindex $argList $i]
881					if {$thisArg == ""} {
882						set wave "all"
883					} elseif {$thisArg == "-show"} {  
884						set wave "all"
885						set show "enable"
886					} else {  
887						set wave $thisArg
888					}
889				} elseif {$thisArg == "-show"} {
890					set show "enable"
891				} else {
892					sal_print_log "WARNING: ignored argument $thisArg"
893					sal_print_log ""
894				}
895				set i [expr $i + 1]
896			}
897	
898			#Check Arguments
899			if {$contains == "All-regex"} {
900				sal_print_log "ERROR: launch_tb: -contains argument is required"
901				return
902			}
903			
904			#Launch
905			variable TbRuns
906			variable RunSuppress
907			foreach run $TbRuns {
908				#Check if TB should be run
909				set runLib [dict get $run TB_LIB]
910				set runName [dict get $run TB_NAME]
911				set skip [dict get $run SKIP]
912				set allArgLists [dict get $run TB_ARGS]
913				if {[string first $contains $runName] == -1} {
914					continue
915				}
916				sal_print_log ""
917				sal_print_log "******************************************************"
918				sal_print_log "*** Launch $runLib.$runName"
919				sal_print_log "******************************************************"
920	
921				#Check if this TB run is not skipped
922				if {([lsearch $skip $Simulator] != -1) || ($skip == "all")} {
923					sal_print_log "!!! Skipped for '$skip' !!!"
924					continue
925				}
926	
927				#Get argument set
928				set argListLength [llength $allArgLists]
929				if {$argidx == "default"} {
930					set argsToUse ""
931				} elseif {$argidx >= $argListLength} {
932					set maxIdx [expr $argListLength-1]
933					sal_print_log "ERROR: launch_tb: -argidx out of range 0 ... $maxIdx"
934					return
935				} else {
936					set argsToUse [lindex $allArgLists $argidx]
937				}
938						
939				#Execute TB for arguments chosen
940				sal_print_log "Launching Simulation"
941				if {"Modelsim" == $Simulator} {
942					#Modelsim -> launch TB
943					sal_launch_tb $runLib $runName $argsToUse $RunSuppress $wave
944				}	
945				if {"GHDL" == $Simulator} {
946					set timeLimit [dict get $run TIME_LIMIT]
947					if {$wave != ""} {
948						set wave "$runName\_$argidx\.ghw"
949						sal_print_log "Writing Waveform: $wave"
950					} 
951					#GHDL -> run TB
952					sal_run_tb $runLib $runName $argsToUse $timeLimit $RunSuppress $wave
953					if {$show == "enable"} {
954						sal_open_wave $wave
955					}
956				}
957	
958				#Only do one TB, return after it was quit
959				return			
960			}
961			
962			#If we arrive here, no TB matched to -contains string
963			sal_print_log "ERROR: launch_tb: -contains <str> did not match any tb_runs!"
964		}
965		namespace export launch_tb	
966	}
